-- ORGANISATEURS — Malagasy Events
-- À exécuter dans Supabase : SQL Editor → New query → coller → Run
-- Les fiches sont modifiables par l'admin officiel ET par le membre propriétaire (owner_id).

create table if not exists public.organisateurs (
  id bigint generated by default as identity primary key,
  name text not null, type text default 'Association', city text default '', region text default '',
  followers text default '', note text default '', fb text default '', insta text default '',
  site text default '', contact text default '',
  owner_id uuid references public.profiles(id) on delete set null
);
alter table public.organisateurs enable row level security;
drop policy if exists "orgas lecture publique" on public.organisateurs;
create policy "orgas lecture publique" on public.organisateurs for select using (true);
drop policy if exists "orgas admin insert" on public.organisateurs;
create policy "orgas admin insert" on public.organisateurs for insert with check (public.is_admin());
drop policy if exists "orgas update admin ou proprietaire" on public.organisateurs;
create policy "orgas update admin ou proprietaire" on public.organisateurs for update
  using (public.is_admin() or auth.uid() = owner_id);
drop policy if exists "orgas admin delete" on public.organisateurs;
create policy "orgas admin delete" on public.organisateurs for delete using (public.is_admin());

